refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
gray = imresize(rgb2gray(image), [160 220]);
smooth = imgaussianblur(gray, [7 7], 1.2);

minima = imextendedmin(smooth, 18, 8);
mprintf("dark valley markers: %d\n", imcountnonzero(minima));

subplot(1, 3, 1);
imshow(gray);
title("Input");
subplot(1, 3, 2);
imshow(smooth);
title("Smoothed");
subplot(1, 3, 3);
imshow(imoverlaymask(gray, minima, [0 80 255], 0.65, %t));
title("Extended minima");
